namespace RecipeCommunity.Models;

public class Recipe
{
    public int Id { get; set; }
    public string Title { get; set; } = string.Empty;
    public string Category { get; set; } = string.Empty;
    public string Ingredients { get; set; } = string.Empty;
    public string Steps { get; set; } = string.Empty;
    public double AverageRating { get; set; }
    public int RatingCount { get; set; }
}

public class RecipeSubmission
{
    public string Title { get; set; } = string.Empty;
    public string Category { get; set; } = string.Empty;
    public string Ingredients { get; set; } = string.Empty;
    public string Steps { get; set; } = string.Empty;
}

using RecipeCommunity.Models;

namespace RecipeCommunity.Services;

public class RecipeService
{
    private readonly List<Recipe> _recipes = new()
    {
        new Recipe { Id = 1, Title = "Classic Margherita Pizza", Category = "Italian", Ingredients = "Pizza dough, San Marzano tomatoes, Fresh mozzarella, Fresh basil, Olive oil, Salt", Steps = "1. Preheat oven to 475°F.\n2. Roll out dough on floured surface.\n3. Spread crushed tomatoes evenly.\n4. Add torn mozzarella pieces.\n5. Bake 10-12 minutes until crust is golden.\n6. Top with fresh basil and drizzle olive oil.", AverageRating = 4.5, RatingCount = 12 },
        new Recipe { Id = 2, Title = "Chicken Tikka Masala", Category = "Indian", Ingredients = "Chicken thighs, Yogurt, Garam masala, Cumin, Tomato sauce, Heavy cream, Ginger, Garlic, Onion", Steps = "1. Marinate chicken in yogurt and spices for 2 hours.\n2. Grill or broil chicken until charred.\n3. Sauté onion, ginger, and garlic.\n4. Add tomato sauce and spices, simmer 15 min.\n5. Stir in cream and add chicken.\n6. Simmer 10 minutes and serve with rice.", AverageRating = 4.8, RatingCount = 24 },
        new Recipe { Id = 3, Title = "Beef Tacos", Category = "Mexican", Ingredients = "Ground beef, Taco shells, Lettuce, Tomato, Cheddar cheese, Sour cream, Taco seasoning", Steps = "1. Brown ground beef in a skillet.\n2. Add taco seasoning and water, simmer 5 min.\n3. Warm taco shells in oven.\n4. Fill shells with beef.\n5. Top with lettuce, tomato, cheese, and sour cream.", AverageRating = 4.2, RatingCount = 8 },
        new Recipe { Id = 4, Title = "Pad Thai", Category = "Asian", Ingredients = "Rice noodles, Shrimp, Eggs, Bean sprouts, Green onions, Peanuts, Tamarind paste, Fish sauce, Sugar, Lime", Steps = "1. Soak rice noodles in warm water 30 min.\n2. Stir-fry shrimp until pink, set aside.\n3. Scramble eggs in wok.\n4. Add drained noodles and sauce (tamarind, fish sauce, sugar).\n5. Toss with shrimp, bean sprouts, and green onions.\n6. Serve with peanuts and lime wedge.", AverageRating = 4.6, RatingCount = 15 },
        new Recipe { Id = 5, Title = "Chocolate Lava Cake", Category = "Desserts", Ingredients = "Dark chocolate, Butter, Eggs, Sugar, Flour, Vanilla extract", Steps = "1. Melt chocolate and butter together.\n2. Whisk eggs and sugar until fluffy.\n3. Fold in chocolate mixture.\n4. Add flour and vanilla, mix gently.\n5. Pour into greased ramekins.\n6. Bake at 425°F for 12-14 minutes.\n7. Invert onto plate and serve immediately.", AverageRating = 4.9, RatingCount = 30 },
        new Recipe { Id = 6, Title = "Caesar Salad", Category = "Salads", Ingredients = "Romaine lettuce, Parmesan cheese, Croutons, Caesar dressing, Lemon, Anchovy paste, Garlic", Steps = "1. Wash and chop romaine lettuce.\n2. Make dressing: whisk anchovy paste, garlic, lemon, and oil.\n3. Toss lettuce with dressing.\n4. Add croutons and shaved parmesan.\n5. Season with black pepper.", AverageRating = 4.0, RatingCount = 6 },
    };

    private readonly Dictionary<int, List<int>> _ratings = new();

    public IReadOnlyList<string> GetCategories()
    {
        return _recipes.Select(r => r.Category).Distinct().OrderBy(c => c).ToList();
    }

    public IReadOnlyList<Recipe> GetRecipesByCategory(string category)
    {
        return _recipes.Where(r => r.Category.Equals(category, StringComparison.OrdinalIgnoreCase)).ToList();
    }

    public Recipe? GetRecipeById(int id)
    {
        return _recipes.FirstOrDefault(r => r.Id == id);
    }

    public void AddRating(int recipeId, int stars)
    {
        if (stars < 1 || stars > 5) return;

        var recipe = _recipes.FirstOrDefault(r => r.Id == recipeId);
        if (recipe is null) return;

        if (!_ratings.ContainsKey(recipeId))
            _ratings[recipeId] = new List<int>();

        _ratings[recipeId].Add(stars);

        var totalRatings = recipe.RatingCount + _ratings[recipeId].Count;
        var totalSum = (recipe.AverageRating * recipe.RatingCount) + _ratings[recipeId].Sum();
        recipe.AverageRating = Math.Round(totalSum / totalRatings, 1);
        recipe.RatingCount = totalRatings;
    }

    public void SubmitRecipe(RecipeSubmission submission)
    {
        var newId = _recipes.Max(r => r.Id) + 1;
        _recipes.Add(new Recipe
        {
            Id = newId,
            Title = submission.Title,
            Category = submission.Category,
            Ingredients = submission.Ingredients,
            Steps = submission.Steps,
            AverageRating = 0,
            RatingCount = 0
        });
    }
}

