arguments.file_text:
@page "/"
@using RecipeCommunity.Services
@inject RecipeService RecipeService

<PageTitle>Recipe Community - Home</PageTitle>

<div class="container mt-4">
    <div class="text-center mb-5">
        <h1 class="display-4">🍳 Recipe Community</h1>
        <p class="lead text-muted">Discover and share delicious recipes from around the world</p>
    </div>

    <h2 class="mb-4">Browse by Category</h2>
    <div class="row">
        @foreach (var category in RecipeService.GetCategories())
        {
            <div class="col-md-4 mb-4">
                <div class="card h-100 shadow-sm">
                    <div class="card-body text-center">
                        <h3 class="card-title">@GetCategoryEmoji(category) @category</h3>
                        <p class="card-text text-muted">
                            @RecipeService.GetRecipesByCategory(category).Count recipe(s)
                        </p>
                        <a href="/category/@category" class="btn btn-outline-primary">Browse Recipes</a>
                    </div>
                </div>
            </div>
        }
    </div>

    <div class="text-center mt-4">
        <a href="/submit" class="btn btn-success btn-lg">📝 Submit a Recipe</a>
    </div>
</div>

@code {
    private string GetCategoryEmoji(string category) => category switch
    {
        "Italian" => "🍕",
        "Indian" => "🍛",
        "Mexican" => "🌮",
        "Asian" => "🍜",
        "Desserts" => "🍰",
        "Salads" => "🥗",
        _ => "🍽️"
    };
}

@page "/category/{CategoryName}"
@using RecipeCommunity.Models
@using RecipeCommunity.Services
@inject RecipeService RecipeService

<PageTitle>@CategoryName Recipes - Recipe Community</PageTitle>

<div class="container mt-4">
    <nav aria-label="breadcrumb">
        <ol class="breadcrumb">
            <li class="breadcrumb-item"><a href="/">Home</a></li>
            <li class="breadcrumb-item active">@CategoryName</li>
        </ol>
    </nav>

    <h1 class="mb-4">@CategoryName Recipes</h1>

    @if (!recipes.Any())
    {
        <div class="alert alert-info">No recipes found in this category.</div>
    }
    else
    {
        <div class="row">
            @foreach (var recipe in recipes)
            {
                <div class="col-md-6 mb-4">
                    <div class="card h-100 shadow-sm">
                        <div class="card-body">
                            <h4 class="card-title">@recipe.Title</h4>
                            <p class="text-muted">
                                ⭐ @recipe.AverageRating.ToString("F1") (@recipe.RatingCount ratings)
                            </p>
                            <a href="/recipe/@recipe.Id" class="btn btn-primary">View Recipe</a>
                        </div>
                    </div>
                </div>
            }
        </div>
    }
</div>

@code {
    [Parameter]
    public string CategoryName { get; set; } = string.Empty;

    private IReadOnlyList<Recipe> recipes = Array.Empty<Recipe>();

    protected override void OnParametersSet()
    {
        recipes = RecipeService.GetRecipesByCategory(CategoryName);
    }
}

@page "/recipe/{Id:int}"
@using RecipeCommunity.Models
@using RecipeCommunity.Services
@inject RecipeService RecipeService

<PageTitle>@(recipe?.Title ?? "Recipe") - Recipe Community</PageTitle>

<div class="container mt-4">
    <nav aria-label="breadcrumb">
        <ol class="breadcrumb">
            <li class="breadcrumb-item"><a href="/">Home</a></li>
            @if (recipe is not null)
            {
                <li class="breadcrumb-item"><a href="/category/@recipe.Category">@recipe.Category</a></li>
                <li class="breadcrumb-item active">@recipe.Title</li>
            }
        </ol>
    </nav>

    @if (recipe is null)
    {
        <div class="alert alert-warning">Recipe not found.</div>
    }
    else
    {
        <h1 class="mb-2">@recipe.Title</h1>
        <p class="text-muted mb-4">Category: @recipe.Category</p>

        <div class="row">
            <div class="col-md-8">
                <div class="card mb-4">
                    <div class="card-header"><h5 class="mb-0">🧾 Ingredients</h5></div>
                    <div class="card-body">
                        <ul class="list-group list-group-flush">
                            @foreach (var ingredient in recipe.Ingredients.Split(',', StringSplitOptions.TrimEntries))
                            {
                                <li class="list-group-item">@ingredient</li>
                            }
                        </ul>
                    </div>
                </div>

                <div class="card mb-4">
                    <div class="card-header"><h5 class="mb-0">👨‍🍳 Steps</h5></div>
                    <div class="card-body">
                        @foreach (var step in recipe.Steps.Split('\n', StringSplitOptions.RemoveEmptyEntries))
                        {
                            <p>@step</p>
                        }
                    </div>
                </div>
            </div>

            <div class="col-md-4">
                <div class="card">
                    <div class="card-header"><h5 class="mb-0">⭐ Rating</h5></div>
                    <div class="card-body text-center">
                        <p class="display-6">@recipe.AverageRating.ToString("F1")</p>
                        <p class="text-muted">@recipe.RatingCount ratings</p>
                        <hr />
                        <p><strong>Rate this recipe:</strong></p>
                        <StarRating RecipeId="@recipe.Id" />
                    </div>
                </div>
            </div>
        </div>
    }
</div>

@code {
    [Parameter]
    public int Id { get; set; }

    private Recipe? recipe;

    protected override void OnParametersSet()
    {
        recipe = RecipeService.GetRecipeById(Id);
    }
}

@rendermode InteractiveServer
@using RecipeCommunity.Services
@inject RecipeService RecipeService

<div class="star-rating">
    @for (int i = 1; i <= 5; i++)
    {
        var star = i;
        <span class="star @(star <= selectedRating ? "selected" : "")"
              @onclick="() => Rate(star)"
              style="cursor: pointer; font-size: 1.5rem;">
            @(star <= selectedRating ? "★" : "☆")
        </span>
    }
</div>

@if (submitted)
{
    <div class="alert alert-success mt-2 py-1 px-2 small">
        Thanks! You rated @selectedRating star(s).
    </div>
}

@code {
    [Parameter]
    public int RecipeId { get; set; }

    private int selectedRating;
    private bool submitted;

    private void Rate(int stars)
    {
        selectedRating = stars;
        submitted = true;
        RecipeService.AddRating(RecipeId, stars);
    }
}

@page "/submit"
@rendermode InteractiveServer
@using RecipeCommunity.Models
@using RecipeCommunity.Services
@inject RecipeService RecipeService

<PageTitle>Submit a Recipe - Recipe Community</PageTitle>

<div class="container mt-4">
    <nav aria-label="breadcrumb">
        <ol class="breadcrumb">
            <li class="breadcrumb-item"><a href="/">Home</a></li>
            <li class="breadcrumb-item active">Submit Recipe</li>
        </ol>
    </nav>

    <h1 class="mb-4">📝 Submit a Recipe</h1>

    @if (submitted)
    {
