@page "/submit"
@rendermode InteractiveServer
@using RecipeCommunity.Models
@using RecipeCommunity.Services
@inject RecipeService RecipeService

<PageTitle>Submit a Recipe - Recipe Community</PageTitle>

<div class="container mt-4">
    <nav aria-label="breadcrumb">
        <ol class="breadcrumb">
            <li class="breadcrumb-item"><a href="/">Home</a></li>
            <li class="breadcrumb-item active">Submit Recipe</li>
        </ol>
    </nav>

    <h1 class="mb-4">📝 Submit a Recipe</h1>

    @if (submitted)
    {
        <div class="alert alert-success">
            <h4>Recipe Submitted!</h4>
            <p>Your recipe "<strong>@submission.Title</strong>" has been added to the community.</p>
            <a href="/" class="btn btn-primary">Back to Home</a>
        </div>
    }
    else
    {
        <div class="row">
            <div class="col-md-8">
                <EditForm Model="submission" OnValidSubmit="HandleSubmit" FormName="recipeForm">
                    <DataAnnotationsValidator />

                    <div class="mb-3">
                        <label for="title" class="form-label">Recipe Title</label>
                        <InputText id="title" class="form-control" @bind-Value="submission.Title"
                                   placeholder="e.g., Grandma's Apple Pie" />
                    </div>

                    <div class="mb-3">
                        <label for="category" class="form-label">Category</label>
                        <InputSelect id="category" class="form-select" @bind-Value="submission.Category">
                            <option value="">-- Select Category --</option>
                            <option value="Italian">Italian</option>
                            <option value="Indian">Indian</option>
                            <option value="Mexican">Mexican</option>
                            <option value="Asian">Asian</option>
                            <option value="Desserts">Desserts</option>
                            <option value="Salads">Salads</option>
                            <option value="Other">Other</option>
                        </InputSelect>
                    </div>

                    <div class="mb-3">
                        <label for="ingredients" class="form-label">Ingredients</label>
                        <InputTextArea id="ingredients" class="form-control" rows="4"
                                       @bind-Value="submission.Ingredients"
                                       placeholder="Comma-separated list, e.g., Flour, Sugar, Butter, Apples" />
                    </div>

                    <div class="mb-3">
                        <label for="steps" class="form-label">Steps</label>
                        <InputTextArea id="steps" class="form-control" rows="6"
                                       @bind-Value="submission.Steps"
                                       placeholder="One step per line, e.g.,&#10;1. Preheat oven to 350°F.&#10;2. Mix dry ingredients..." />
                    </div>

                    <button type="submit" class="btn btn-success btn-lg"
                            disabled="@(string.IsNullOrWhiteSpace(submission.Title) || string.IsNullOrWhiteSpace(submission.Category))">
                        Submit Recipe
                    </button>
                </EditForm>
            </div>
        </div>
    }
</div>

@code {
    private RecipeSubmission submission = new();
    private bool submitted;

    private void HandleSubmit()
    {
        if (string.IsNullOrWhiteSpace(submission.Title) || string.IsNullOrWhiteSpace(submission.Category))
            return;

        RecipeService.SubmitRecipe(submission);
        submitted = true;
    }
}

